import { AbstractEditor } from './abstract.editor.js';

/** 段落行内编辑器。使用 contenteditable div。 */
export class ParagraphEditor extends AbstractEditor {

  protected _createEditor(): HTMLElement {
    const div = Object.assign(document.createElement('div'), {
      className: 'paragraph-editor',
      innerHTML: this._markedRoot.innerHTML
    });
    div.style.cssText = 'border:1px solid #90caf9;border-radius:6px;padding:8px;outline:none;';
    return div;
  }

  mount(): void {
    super.mount();
    this._editor.contentEditable = 'true';
  }

  protected _commitCollect(): { raw: string; html: string } {
    const text = this._editor.textContent || '';
    return { raw: text, html: text };
  }
}
