import { EditorView, keymap, lineNumbers } from '@codemirror/view';
import { defaultKeymap } from '@codemirror/commands';
import { defaultHighlightStyle, syntaxHighlighting } from '@codemirror/language';
import { EditorState } from '@codemirror/state';
import { AbstractEditor, type EditorCallbacks } from './abstract.editor.js';

/** CM6 视图缓存条目 */
export interface CmViewEntry {
    view: EditorView;
    marked: string;
}

/** 只读预览 CM6 布局主题（语法着色由 syntaxHighlighting(defaultHighlightStyle) 提供） */
const PREVIEW_THEME = EditorView.theme({
  '&': {
    backgroundColor: '#ebfdff',
    fontFamily: '"Cascadia Code","Fira Code",Consolas,monospace',
    fontSize: '13px',
    lineHeight: '1.5',
    borderRadius: '6px',
  },
  '.cm-scroller': {
    padding: '12px 16px',
    overflow: 'auto',
  },
  '.cm-content': {
    padding: '0',
    whiteSpace: 'pre-wrap',
  },
  '.cm-line': {
    padding: '0',
  },
  '.cm-gutters': { display: 'none' },
  '.cm-activeLine, .cm-activeLineGutter': { backgroundColor: 'transparent' },
  '.cm-cursor, .cm-dropCursor': { display: 'none !important' },
  '.cm-selectionBackground': { backgroundColor: 'transparent !important' },
}, { dark: false });

/**
 * 通用代码块编辑器（fence_*）。
 *
 * 双模式设计：
 * - **预览模式**（无 callbacks）：批量创建只读 CM6 语法高亮视图，替代 `<pre><code>` 占位元素。
 * - **编辑模式**（有 callbacks）：可编辑 CM6 视图 + 语言选择工具栏 + 提交/取消/删除生命周期。
 *
 * 使用方式：
 * ```
 * // 预览模式
 * const previewer = new FenceEditor(renderRoot);
 * previewer.mount();
 *
 * // 编辑模式
 * const editor = new FenceEditor(block, callbacks);
 * editor.mount();
 * ```
 */
export class FenceEditor extends AbstractEditor {
  private _lang: string = '';
  private _cmView: EditorView | null = null;

  /** CM6 只读视图缓存 Map（<pre> → {view, marked}） */
  private _cmViews: Map<HTMLElement, CmViewEntry> = new Map();
  /** 预览模式 CM6 主题 */
  private _theme: any = null;

  /**
   * 统一构造入口。
   * - **编辑模式**：`callback` 为 {@link EditorCallbacks}，`element` 为被编辑的 fence block
   * - **预览模式**：不传 `callback`，`element` 为宿主 renderRoot，主题使用内置默认值
   */
  constructor(element: HTMLElement, callback?: EditorCallbacks) {
    super(element, callback);
    const isEditor = callback && typeof callback === 'object' && 'onCommit' in callback;
    if (isEditor) {
      const raw = element.getAttribute('data-marked') || '';
      this._lang = this._parseFence(raw).lang;
    } else {
      this._theme = PREVIEW_THEME;
    }
  }

  /** 从 fence block 的 data-marked 中提取语言标识符和纯代码内容 */
  private _parseFence(raw: string): { lang: string; code: string } {
    const lines = raw.replace(/\r\n/g, '\n').split('\n');
    while (lines.length > 0 && lines[lines.length - 1] === '') {
      lines.pop();
    }
    if (lines.length === 0) return { lang: '', code: '' };
    const first = lines[0] || '';
    const lang = first.replace(/^`{3,}\s*/, '').trim();
    const hasClose = lines.length >= 2 && /^`{3,}\s*$/.test(lines[lines.length - 1]);
    const codeLines = lines.slice(1, hasClose ? -1 : lines.length);
    return { lang, code: codeLines.join('\n') };
  }

  protected _createEditor(): HTMLElement {
    const container = document.createElement('div');
    container.className = 'fence-editor-cm';
    return container;
  }

  /**
   * 统一挂载入口。
   * - **编辑模式**（有 callbacks）：打开编辑器。
   * - **预览模式**（无 callbacks）：扫描 `_markedRoot` 下所有代码块创建 CM6 只读视图。
   *
   * @returns 预览模式下返回是否找到代码块；编辑模式下无返回值
   */
  mount(): boolean | void {
    if (this._callbacks) {
      // 编辑模式
      super.mount();
      const raw = this._markedRoot.getAttribute('data-marked') || '';
      const { code } = this._parseFence(raw);
      this._createLangToolbar();
      this._mountEditor(code);
      this._cmView!.focus();
    } else {
      // 预览模式
      return this._mountPreview();
    }
  }

  /** 预览模式：扫描 _markedRoot 下的代码块并创建 CM6 只读 EditorView */
  private _mountPreview(): boolean {
    const root = this._markedRoot;
    if (!root) return false;
    const panes = Array.from(root.querySelectorAll<HTMLElement>('.preview-pane'));
    if (panes.length === 0) return false;
    const seen = new Set<HTMLElement>();
    let found = false;

    panes.forEach(pane => {
      const codeEls = pane.querySelectorAll<HTMLElement>('pre > code[data-lang]');
      codeEls.forEach(codeEl => {
        found = true;
        const pre = codeEl.parentElement!;
        seen.add(pre);

        const mdtypeBlock = pre.closest('[data-type]');
        const marked = mdtypeBlock?.getAttribute('data-marked') ?? '';

        const existing = this._cmViews.get(pre);
        if (existing && existing.marked === marked) return;
        if (existing) existing.view.destroy();

        const lang = codeEl.getAttribute('data-lang') ?? '';
        const code = codeEl.textContent ?? '';
        const langSupport = AbstractEditor.getLanguageExtension(lang);

        pre.textContent = '';

        try {
          const view = new EditorView({
            doc: code,
            extensions: [
              langSupport ?? [],
              syntaxHighlighting(defaultHighlightStyle),
              EditorState.readOnly.of(true),
              EditorView.editable.of(false),
              EditorView.lineWrapping,
              this._theme,
            ].filter(Boolean),
            parent: pre,
          });
          this._cmViews.set(pre, { view, marked });
        } catch (err) {
          pre.textContent = code;
          console.warn('[x-markdown] CM6 mount failed for lang=%s: %o', lang, err);
        }
      });
    });

    for (const [pre, entry] of this._cmViews) {
      if (!pre.isConnected) {
        entry.view.destroy();
        this._cmViews.delete(pre);
      }
    }

    return found;
  }

  /** 在 _actions 前插入语言选择下拉框 */
  private _createLangToolbar(): void {
    const select = document.createElement('select');
    select.style.cssText = 'padding:2px 4px;border:1px solid #90caf9;border-radius:4px;font-size:12px;background:#fff;';

    const languages = AbstractEditor.getSupportedLanguages();
    const normalizedCurrent = AbstractEditor.normalizeLang(this._lang);
    const options = ['', ...languages];
    for (const lang of options) {
      const option = document.createElement('option');
      option.value = lang;
      option.textContent = lang || '(纯文本)';
      if (lang === normalizedCurrent) option.selected = true;
      select.appendChild(option);
    }

    select.addEventListener('change', () => {
      this._lang = select.value;
      const code = this._cmView?.state.doc.toString() ?? '';
      this._cmView?.destroy();
      this._mountEditor(code);
      this._cmView!.focus();
    });

    this._toolbar.appendChild(select);
  }

  /** 创建 CM6 EditorView */
  private _mountEditor(code: string): void {
    const langSupport = AbstractEditor.getLanguageExtension(this._lang);
    const self = this;

    this._cmView = new EditorView({
      doc: code,
      extensions: [
        langSupport ?? [],
        syntaxHighlighting(defaultHighlightStyle),
        lineNumbers(),
        EditorView.lineWrapping,
        keymap.of([
          { key: 'Escape', run: () => { self.close(); return true; } },
          { key: 'Ctrl-Enter', run: () => { self.commit(); return true; } },
          ...defaultKeymap,
        ]),
        EditorView.theme({
          '&': { maxHeight: '400px', border: '1px solid #90caf9', borderRadius: '6px', fontSize: '13px' },
          '.cm-scroller': { overflow: 'auto' },
        }),
      ],
      parent: this._editor,
    });
  }

  protected _commitCollect(): { raw: string; html: string } {
    const code = this._cmView?.state.doc.toString() ?? '';
    const raw = '```' + this._lang + '\n' + code + '\n```';
    const html = AbstractEditor.highlight(this._lang, code);
    return { raw, html };
  }

  protected _destroyEditor(): void {
    this._cmView?.destroy();
    this._cmView = null;
  }
}
