import { CSSResult, html } from 'lit';
import { property } from 'lit/decorators.js';
import { unsafeHTML } from 'lit/directives/unsafe-html.js';
import MarkdownIt from 'markdown-it';
import { AbstractEditor, EditorCallbacks } from './abstract.editor.js';
import { ParagraphEditor } from './paragraph.editor.js';
import { FenceEditor } from './fence.editor.js';
import { HtmlEditor } from './html.editor.js';
import styles from './markdown.style.js';
import XUIElement from '../../internal/abstract.js';
import { util } from '../../internal/utils.js';

/**
 * Markdown 渲染与编辑组件。
 *
 * <h3>核心功能</h3>
 * <ul>
 *   <li><b>渲染</b> — 基于 markdown-it 将 Markdown 解析为 HTML，支持代码语法高亮（CM6）</li>
 *   <li><b>编辑</b> — 双击 block 进入行内编辑，支持段落、代码块、HTML 块三种编辑器</li>
 *   <li><b>资源</b> — 支持远程加载 .md 文件，自动为相对路径资源添加前缀</li>
 *   <li><b>源预览</b> — 工具栏按钮打开 x-window 查看/编辑 Markdown 源内容</li>
 * </ul>
 *
 * <h3>DOM 结构</h3>
 * <pre>
 *   &lt;x-markdown&gt;
 *     ├── .toolbar          ← 编辑/源预览/保存/重载
 *     └── .x-body
 *          └── .preview-pane.markdown-body
 *               ├── [data-type][data-id][data-marked]  ← block 包装元素
 *               └── ...
 * </pre>
 */
export default class XMarkdown extends XUIElement {
  /** markdown-it 实例，静态单例——无状态，所有组件实例共享 */
  private static readonly markdown = new MarkdownIt({
    html: true, breaks: true, linkify: true,
    highlight: (str: string, lang: string): string => AbstractEditor.highlight(lang, str)
  });

  /** 组件样式（Shadow DOM 隔离） */
  static styles: CSSResult = styles;

  static defaultOptions = {
    autoLoad: true,
    /** Markdown 资源文件请求的固定前缀，系统平台通过该前缀拦截并处理 Markdown 资源请求。 */
    resPrefix: '',
    /** 保存 Markdown 内容的 URL，设置后工具栏显示保存按钮。 */
    saveUrl: '',
  };

  /** Markdown 文本内容（非响应式，仅 loadFromURL 时手动触发渲染；编辑器提交时直接更新不重渲染） */
  content: string = '';

  /** 远程 Markdown 文件 URL */
  @property({ type: String }) url: string = '';

  /** 加载状态 */
  @property({ type: Boolean, reflect: true }) loading: boolean = false;

  /** 加载错误信息 */
  @property({ type: String }) loadError: string = '';

  /** 保存状态 */
  @property({ type: Boolean }) saving: boolean = false;

  /** 当前模式：false 为浏览状态，true 为编辑状态 */
  @property({ type: Boolean, reflect: true }) editing: boolean = false;

  /** 当前解析中的原始文本行（仅 parseMarkdown → renderBlock 调用链期间有效） */
  private _parseLines: string[] = [];

  /** 缓存所有 [data-type] 块元素（data-id → HTMLElement），渲染后一次性收集。Map 保证插入/迭代顺序一致，同时支持 O(1) 按 ID 查找。 */
  private _mdBlocks: Map<string, HTMLElement> = new Map();

  /** Fence 代码块预览渲染器实例（复用，管理 CM6 只读视图缓存） */
  private _fencePreviewer: FenceEditor | null = null;

  /** 源内容预览窗口引用，用于关闭时清理 ResizeObserver */
  private _sourceWin: HTMLElement | null = null;

  /** data-type → 编辑器类的注册表。以 `fence_` 为前缀的键匹配所有 fence_* 类型。 */
  private static readonly _editors: Record<string, new (b: HTMLElement, c: EditorCallbacks) => { mount(): void }> = {
    'paragraph_open': ParagraphEditor,
    'fence_': FenceEditor,
    'fence': FenceEditor,
    'html_block': HtmlEditor,
  };

  /** 组件初始化：若设置了 url 且未禁用 autoLoad，自动加载远程 Markdown 内容 */
  initialize(): void {
    super.initialize();

    if (this.url && this.options.autoLoad) {
      this.loadFromURL(this.url);
    }
  }

  willUpdate(changed: Map<string, any>): void {
    super.willUpdate(changed);
  }

  /** 每次渲染后刷新 _mdBlocks 缓存，挂载 CM6 视图。 */
  updated(changed: Map<string, any>): void {
    super.updated(changed);
    this.collectMdBlocks();
    if (!this._fencePreviewer) {
      this._fencePreviewer = new FenceEditor(this.renderRoot as HTMLElement);
    }
    this._fencePreviewer.mount();
  }

  /**
   * 将 Markdown 文本解析为 HTML，每个顶层 block 元素包装 data-type、data-marked 属性，
   * 记录生成该 HTML 片段的原始 markdown 源码，建立 HTML↔markdown 双向映射。
   *
   * <p>markdown-it 的 token 模型以 open/close 成对出现（如 heading_open / heading_close），
   * token.map = [startLine, endLine] 提供精确到行的源码定位，从原始文本按行切分重建 raw。</p>
   *
   * <p>自定义嵌入块：fenced code block 的 info 字符串（如 x-chart）保留为 data-type 值。</p>
   */
  private parseMarkdown(content: string): string {
    if (!content) return '';
    const normalized = content.replace(/\\n/g, '\n');
    this._parseLines = normalized.split('\n');

    const parts: string[] = [];

    const tokens = XMarkdown.markdown.parse(normalized, {});
    for (let i = 0; i < tokens.length; i++) {
      const token = tokens[i];

      // 独立的单 token block：html_block、hr、fence（代码块）
      if (token.type === 'html_block' || token.type === 'hr' || token.type === 'fence') {
        parts.push(this.renderBlock([token], token));
        continue;
      }

      // inline 内容由 wrapping block 渲染，不单独处理
      if (token.type === 'inline') continue;

      // 匹配 open 型 token（如 heading_open、paragraph_open 等）
      if (token.type.endsWith('_open')) {
        const closeType = token.type.replace('_open', '_close');

        // 收集该 block 内的所有 token（从 open 到对应的 close）
        const blockTokens: any[] = [token];
        while (++i < tokens.length && tokens[i].type !== closeType) {
          blockTokens.push(tokens[i]);
        }
        if (i < tokens.length) {
          blockTokens.push(tokens[i]); // close token
        }

        parts.push(this.renderBlock(blockTokens, token));
      }
    }
    return parts.join('\n');
  }

  /**
   * 将单个 block 的完整 token 数组渲染为 HTML 包装元素。
   * 子类可重写此方法为不同 block 类型添加编辑工具栏、编辑界面等交互功能。
   *
   * @param tokens 该 block 的完整 token 数组（含 open、子 token、close；standalone 类型为单元素数组）
   * @param token  该 block 的起始 token，用于推导 data-type 值
   * @return 包装后的 HTML 字符串
   */
  protected renderBlock(tokens: any[], token: any): string {
    if (!tokens || tokens.length === 0) return '';

    const first = tokens[0];
    const raw = first.map ? this._parseLines.slice(first.map[0], first.map[1]).join('\n') : '';

    // fence 带 info 时拼接为 "fence_语言名"（如 fence_xml、fence_java），其余直接用 token.type
    let dataType = token.type;
    if (dataType === 'fence' && token.info) {
      dataType = dataType + '_' + token.info;
    }

    const html = XMarkdown.markdown.renderer.render(tokens, XMarkdown.markdown.options, {});
    return `<div data-id="${util.guid()}" data-type="${dataType}" data-marked="${this.escapeAttr(raw)}">${html}</div>`;
  }

  /**
   * 从 URL 加载 Markdown 内容。
   * @param url 资源地址
   */
  async loadFromURL(url: string): Promise<void> {
    this.loading = true;
    this.loadError = '';
    this.url = url;
    try {
      const response = await fetch(url);
      if (!response.ok) {
        throw new Error(`Failed to load markdown: ${response.status} ${response.statusText}`);
      }
      this.content = await response.text();
      this.requestUpdate(); // content 非响应式，手动触发渲染
      this.emit('x-markdown-load', { detail: { url, content: this.content } });
    } catch (err: any) {
      this.loadError = err.message || 'Unknown error loading markdown';
    } finally {
      this.loading = false;
    }
  }

  /**
   * 为 Markdown 中的资源引用 URL 添加固定前缀。
   * 处理相对路径，外部链接和已有前缀的 URL 不处理。
   * 生成的 URL 会去掉原有查询参数，附加当前窗口的查询参数。
   */
  private replaceUriPrefix(resourceUrl: string, basePath: string): string {
    if (!resourceUrl || this.isExternalUrl(resourceUrl) || this.hasUriPrefix(resourceUrl)) {
      return resourceUrl;
    }
    let path: string;
    if (resourceUrl.startsWith('./') || resourceUrl.startsWith('../') || (!resourceUrl.startsWith('/') && !/^(https?:)?\/\//i.test(resourceUrl) && !/^[a-zA-Z]:[/\\]/.test(resourceUrl))) {
      path = resourceUrl;
    } else {
      try {
        path = new URL(resourceUrl, new URL(basePath, window.location.origin)).pathname;
      } catch {
        path = resourceUrl.replace(/^\.?\//, '');
      }
    }
    const q = path.indexOf('?');
    if (q > -1) path = path.substring(0, q);
    const href = window.location.href;
    const qi = window.location.href.indexOf('?');
    const search = qi > -1 ? href.substring(qi) : '';
    return this.options.resPrefix + path.replace(/^\//, '') + search;
  }

  /** 重写 HTML 片段中的资源引用 URL（src / href），添加 Markdown 资源前缀。 */
  private rewriteURLs(html: string, basePath: string): string {
    html = html.replace(/(src=)"([^"]+)"/gi, (_match, prefix, url) =>
      `${prefix}"${this.replaceUriPrefix(url, basePath)}"`);
    html = html.replace(/(href=)"([^"]+)"/gi, (_match, prefix, url) =>
      `${prefix}"${this.replaceUriPrefix(url, basePath)}"`);
    return html;
  }

  /** 解析 Markdown 内容为 HTML，若设置了 resPrefix 则将资源引用重写为带前缀的路径。 */
  private toHtml(content: string): string {
    const html = this.parseMarkdown(content);
    if (this.options.resPrefix) {
      return this.rewriteURLs(html, this.url || '');
    }
    return html;
  }

  /**
   * 保存 Markdown 内容到服务器。
   */
  private async onSave(): Promise<void> {
    const saveUrl = this.options.saveUrl;
    if (!saveUrl)
      return;

    this.saving = true;
    try {
      const formData = new FormData();
      formData.append('content', this.content);
      const response = await fetch(saveUrl, { method: 'POST', body: formData });
      if (!response.ok) {
        throw new Error(`Save failed: ${response.status} ${response.statusText}`);
      }
      this.emit('x-markdown-save', { detail: { content: this.content } });
    } catch (err: any) {
      this.emit('x-markdown-save-error', { detail: { error: err.message || 'Unknown error' } });
    } finally {
      this.saving = false;
    }
  }

  /** 打开 x-window 预览/编辑 Markdown 源内容，窗口靠右、底部对齐，高度跟随 XMarkdown 变化 */
  private onPreviewSource(): void {
    // 关闭已打开的窗口
    if (this._sourceWin) {
      (this._sourceWin as any).close?.();
      this._sourceWin = null;
    }

    const rect = this.getBoundingClientRect();
    const win = document.createElement('x-window') as any;
    win.setAttribute('x-options', 'title:"Markdown 源内容",destroy:true');
    win.style.cssText = `position:fixed;right:0;bottom:0;width:800px;height:${rect.height}px;display:flex;flex-direction:column;`;
    win.innerHTML = `
      <span slot="icon" id="md-source-save" title="保存并应用" style="cursor:pointer;display:inline-flex;align-items:center;padding:0 4px;">
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="16" height="16" fill="currentColor"><path d="M2 1a1 1 0 0 0-1 1v12a1 1 0 0 0 1 1h12a1 1 0 0 0 1-1V4.414a1 1 0 0 0-.293-.707l-2.414-2.414A1 1 0 0 0 11.586 1H2zm0 1h1v4.5A1.5 1.5 0 0 0 4.5 8h5A1.5 1.5 0 0 0 11 6.5V2h.586L14 4.414V14H2V2zm2 0v4.5a.5.5 0 0 0 .5.5h5a.5.5 0 0 0 .5-.5V2H4zm2 10.5V11h4v1.5a.5.5 0 0 1-.5.5h-3a.5.5 0 0 1-.5-.5z"/></svg>
      </span>
      <pre contenteditable="true" style="margin:0;padding:16px;white-space:pre;background:#eefaff;font-family:'Cascadia Code','Fira Code',Consolas,monospace;font-size:13px;line-height:1.5;outline:none;">${this.escapeAttr(this.content)}</pre>`;
    win.open?.(document.body);
    this._sourceWin = win;

    // 绑定保存按钮事件
    const saveBtn = win.querySelector('#md-source-save');
    const pre = win.querySelector('pre');
    if (saveBtn && pre) {
      saveBtn.addEventListener('click', () => {
        this.content = pre.textContent || '';
        this.requestUpdate();
        this._sourceWin = null;
        win.close?.();
      });
    }

    // 监听 XMarkdown 尺寸变化，同步调整窗口高度
    const ro = new ResizeObserver(() => {
      const h = this.getBoundingClientRect().height;
      if (h > 0) win.style.height = `${h}px`;
    });
    ro.observe(this);
    // 窗口关闭/销毁时停止监听
    const cleanup = () => { ro.disconnect(); this._sourceWin = null; };
    win.addEventListener('close', cleanup, { once: true });
    // MutationObserver 兜底：窗口从 DOM 移除时清理
    const mo = new MutationObserver(() => {
      if (!win.isConnected) { cleanup(); mo.disconnect(); }
    });
    mo.observe(document.body, { childList: true });
  }

  /** 渲染工具栏：编辑切换、源内容预览、保存、重载按钮 */
  private renderToolbar() {
    const icEdit = html`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="18" height="18" fill="currentColor"><path d="M12.146.146a.5.5 0 0 1 .708 0l3 3a.5.5 0 0 1 0 .708l-10 10a.5.5 0 0 1-.168.11l-5 2a.5.5 0 0 1-.65-.65l2-5a.5.5 0 0 1 .11-.168l10-10zM11.207 2.5 13.5 4.793 14.793 3.5 12.5 1.207 11.207 2.5zm1.586 2.793L10.5 3 4 9.5V10h.5l.5-.5 7.793-7.793zM3 10.707v1.586l1.586.293.293-1.586L4.293 10l-1.293.707z"/></svg>`;
    const icReload = html`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="18" height="18" fill="currentColor"><path fill-rule="evenodd" d="M8 3a5 5 0 1 0 4.546 2.914.5.5 0 0 1 .908-.417A6 6 0 1 1 8 2v1z"/><path d="M8 4.466V.534a.25.25 0 0 1 .41-.192l2.36 1.966c.12.1.12.284 0 .384L8.41 4.658A.25.25 0 0 1 8 4.466z"/></svg>`;
    const icSave = html`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="18" height="18" fill="currentColor"><path d="M2 1a1 1 0 0 0-1 1v12a1 1 0 0 0 1 1h12a1 1 0 0 0 1-1V4.414a1 1 0 0 0-.293-.707l-2.414-2.414A1 1 0 0 0 11.586 1H2zm0 1h1v4.5A1.5 1.5 0 0 0 4.5 8h5A1.5 1.5 0 0 0 11 6.5V2h.586L14 4.414V14H2V2zm2 0v4.5a.5.5 0 0 0 .5.5h5a.5.5 0 0 0 .5-.5V2H4zm2 10.5V11h4v1.5a.5.5 0 0 1-.5.5h-3a.5.5 0 0 1-.5-.5z"/></svg>`;
    const icSource = html`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16" width="18" height="18" fill="currentColor"><path fill-rule="evenodd" d="M4.72 3.22a.75.75 0 0 1 1.06 1.06L2.06 8l3.72 3.72a.75.75 0 1 1-1.06 1.06L.47 8.53a.75.75 0 0 1 0-1.06l4.25-4.25zm6.56 0a.75.75 0 1 0-1.06 1.06L13.94 8l-3.72 3.72a.75.75 0 1 0 1.06 1.06l4.25-4.25a.75.75 0 0 0 0-1.06l-4.25-4.25z"/></svg>`;

    return html`
      <div class="toolbar">
        <slot name="toolbar"></slot>
        <span style="display:flex;gap:4px;">
          <button class="toolbar-btn" @click="${this.onPreviewSource}" title="源内容">
            ${icSource}
          </button>
          ${this.options.saveUrl ? html`
            <button class="toolbar-btn" @click="${this.onSave}" ?disabled="${this.saving}" title="保存">
              ${icSave}
            </button>
          ` : ''}
          ${this.url ? html`
            <button class="toolbar-btn" @click="${() => this.loadFromURL(this.url)}" title="重新加载">
              ${icReload}
            </button>
          ` : ''}
          <button class="toolbar-btn" style="margin-left:50px;${this.editing ? 'background:#b3e5fc;' : ''}" @click="${this.onToggleEdit}" title="${this.editing ? '退出编辑' : '编辑'}">
            ${icEdit}
          </button>
        </span>
      </div>
    `;
  }

  /** 切换编辑/浏览状态：编辑模式下双击 block 可打开行内编辑器 */
  private onToggleEdit(): void {
    this.editing = !this.editing;
  }

  /** 渲染 Markdown 预览区：解析 content → HTML，通过 unsafeHTML 注入 DOM，绑定双击编辑事件 */
  private renderPreview() {
    const htmlContent = this.toHtml(this.content);
    return html`
      <div class="preview-pane markdown-body" @dblclick="${this.onPreviewDbClick}">
        ${this.content ? unsafeHTML(htmlContent) : html`<span style="color:#999">暂无内容</span>`}
      </div>
    `;
  }

  /** 双击 block 时，沿 DOM 树向上查找 data-type 并调度对应编辑器。仅在编辑状态下生效。支持前缀匹配（如 fence_ 匹配 fence_xml、fence_java 等）。 */
  private onPreviewDbClick(e: MouseEvent): void {
    if (!this.editing) return;
    const block = (e.target as HTMLElement).closest('[data-type]');
    if (!block || block.classList.contains('is-editing')) return;

    const mdtype = block.getAttribute('data-type') || '';
    const EditorClass = XMarkdown._resolveEditor(mdtype);
    if (!EditorClass) return;

    const editor = new EditorClass(block as HTMLElement, {
      onCommit: (_text: string) => {
        const parts: string[] = [];
        for (const el of this._mdBlocks.values()) {
          const raw = (el.getAttribute('data-marked') || '').replace(/^\n+|\n+$/g, '');
          if (raw) parts.push(raw);
        }
        // 更新 content 触发 updated() → mount() 全量刷新 CM6 视图
        this.content = parts.join('\n\n');
      },
      onClose: () => { /* no-op */ },
      onDelete: () => {
        this._fencePreviewer!.mount();
      },
      transform: (html: string) => {
        // 当Editor提交时对url执行处理
        return this.options.resPrefix ? this.rewriteURLs(html, this.url || '') : html;
      },
    });
    editor.mount();
  }

  /**
   * 收集预览区中所有 [data-type] 块元素，重建 _mdBlocks 缓存。
   * 每次渲染后调用，保证缓存的 DOM 引用始终指向当前文档中的元素。
   */
  private collectMdBlocks(): void {
    const pane = this.renderRoot.querySelector('.preview-pane');
    this._mdBlocks.clear();
    if (pane) {
      for (const el of pane.querySelectorAll<HTMLElement>('[data-type]')) {
        const id = el.getAttribute('data-id');
        if (id) this._mdBlocks.set(id, el);
      }
    }
  }

  /** 根据 data-id 在指定块之后插入新块，通过重建 Map 保持插入顺序 */
  insertBlockAfter(afterId: string, element: HTMLElement): void {
    const id = element.getAttribute('data-id');
    if (!id) return;
    const entries = [...this._mdBlocks.entries()];
    const idx = entries.findIndex(([k]) => k === afterId);
    entries.splice(idx >= 0 ? idx + 1 : entries.length, 0, [id, element]);
    this._mdBlocks = new Map(entries);
  }

  /** 根据 data-type 解析编辑器类：精确匹配优先，否则前缀匹配 */
  private static _resolveEditor(mdtype: string): (new (b: HTMLElement, c: EditorCallbacks) => { mount(): void }) | undefined {
    if (XMarkdown._editors[mdtype]) {
      return XMarkdown._editors[mdtype];
    }
    for (const [key, cls] of Object.entries(XMarkdown._editors)) {
      if (mdtype.startsWith(key)) {
        return cls;
      }
    }
    return undefined;
  }

  /** 渲染组件：工具栏 + 加载状态/错误提示 + Markdown 预览区 */
  render() {
    return html`
      <div class="x-root">
        ${this.renderToolbar()}
        <div class="x-body">
          ${this.loading ? html`<div class="loading-overlay">加载中...</div>` : ''}
          ${this.loadError ? html`<div class="load-error">${this.loadError}</div>` : ''}
          ${this.renderPreview()}
        </div>
      </div>
    `;
  }

  /**
   * 转义文本中的 &、<、" 字符，使其可安全放入 HTML 属性值中。
   * @returns 转义后的文本
   */
  private escapeAttr(text: string): string {
    return text
      .replace(/&/g, '&amp;')
      .replace(/"/g, '&quot;')
      .replace(/</g, '&lt;');
  }

  /**
   * 判断 URL 是否为外部链接。
   * @returns true 表示 HTTP(S)、data URI、锚点等无需加前缀的 URL
   */
  private isExternalUrl(url: string): boolean {
    return /^(https?:)?\/\//i.test(url) || url.startsWith('data:') || url.startsWith('#');
  }

  /**
   * 判断 URL 是否无需添加 resPrefix。
   * @returns true 表示已是绝对路径、完整 URL、本地磁盘路径或已含前缀
   */
  private hasUriPrefix(url: string): boolean {
    return /^(https?:)?\/\//i.test(url) || url.startsWith('/') || /^[a-zA-Z]:[/\\]/.test(url) || (!!this.options.resPrefix && url.startsWith(this.options.resPrefix));
  }

}
