/* ────────────────────────── 生命周期回调接口 ────────────────────────── */

/** 编辑器生命周期回调。宿主组件注入此接口响应编辑器的提交、关闭、删除事件。 */
export interface EditorCallbacks {
  /** 编辑提交时回调，参数为规范化后的 raw markdown 文本 */
  onCommit: (text: string) => void;
  /** 编辑器关闭时回调（取消或提交后均会触发） */
  onClose: () => void;
  /** 删除当前 block 时回调 */
  onDelete?: () => void;
  /** 提交时对渲染 HTML 做最终转换（如重写资源 URL），在 innerHTML 赋值前调用 */
  transform?: (html: string) => string;
}

/* ────────────────────────── CM6 语言注册表 ────────────────────────── */

/** 语言别名 → 标准名称映射表 */
const LANG_ALIASES: Record<string, string> = {
  'js': 'javascript', 'ts': 'typescript', 'jsx': 'javascript', 'tsx': 'typescript',
  'py': 'python', 'yml': 'yaml', 'sh': 'shell', 'bash': 'shell', 'zsh': 'shell',
  'html': 'xml', 'svg': 'xml', 'xhtml': 'xml', 'md': 'markdown',
  'ps1': 'powershell', 'pwsh': 'powershell', 'rb': 'ruby', 'rs': 'rust',
  'docker': 'dockerfile', 'patch': 'diff', 'conf': 'properties', 'ini': 'properties',
  'c': 'c', 'cpp': 'cpp', 'c++': 'cpp', 'h': 'c',
  'cs': 'csharp', 'c#': 'csharp', 'scala': 'scala', 'kotlin': 'kotlin',
};

/** 惰性初始化标记 */
let _registryInitialized = false;

/** 标准语言名 → LanguageSupport 注册表 */
const _langRegistry: Record<string, LanguageSupport> = {};

/** 将语言标识符归一化为注册表键名（小写 + 别名映射） */
function _normalizeLang(lang: string): string {
  const lower = lang.toLowerCase();
  return LANG_ALIASES[lower] ?? lower;
}

/** 惰性初始化语言注册表，仅首次调用执行 */
function _initRegistry(): void {
  if (_registryInitialized) return;
  _registryInitialized = true;

  _langRegistry['javascript'] = javascript();
  _langRegistry['typescript'] = javascript({ typescript: true });
  _langRegistry['xml'] = xml();
  _langRegistry['json'] = json();
  _langRegistry['sql'] = sql();
  _langRegistry['python'] = python();
  _langRegistry['java'] = java();
  _langRegistry['css'] = css();
  _langRegistry['markdown'] = markdown();
  _langRegistry['shell'] = new LanguageSupport(StreamLanguage.define(shell));
  _langRegistry['yaml'] = new LanguageSupport(StreamLanguage.define(yaml));
  _langRegistry['dockerfile'] = new LanguageSupport(StreamLanguage.define(dockerFile));
  _langRegistry['diff'] = new LanguageSupport(StreamLanguage.define(diff));
  _langRegistry['properties'] = new LanguageSupport(StreamLanguage.define(properties));
  _langRegistry['groovy'] = new LanguageSupport(StreamLanguage.define(groovy));
  _langRegistry['powershell'] = new LanguageSupport(StreamLanguage.define(powerShell));
  _langRegistry['go'] = new LanguageSupport(StreamLanguage.define(go));
  _langRegistry['rust'] = new LanguageSupport(StreamLanguage.define(rust));
  _langRegistry['ruby'] = new LanguageSupport(StreamLanguage.define(ruby));
  _langRegistry['swift'] = new LanguageSupport(StreamLanguage.define(swift));
  _langRegistry['c'] = new LanguageSupport(StreamLanguage.define(c));
  _langRegistry['cpp'] = new LanguageSupport(StreamLanguage.define(cpp));
  _langRegistry['csharp'] = new LanguageSupport(StreamLanguage.define(csharp));
  _langRegistry['scala'] = new LanguageSupport(StreamLanguage.define(scala));
  _langRegistry['kotlin'] = new LanguageSupport(StreamLanguage.define(kotlin));
}

/* ────────────────────────── AbstractEditor ────────────────────────── */

/**
 * Markdown block 行内编辑器抽象基类。
 *
 * 双模式设计：
 * - **编辑器模式**（传 callbacks）：在 `_markedRoot` 内部构建工具栏 + 编辑区，
 *   子类覆写 `_createEditor` / `_commitCollect` 实现具体编辑逻辑。
 * - **渲染器模式**（不传 callbacks）：仅存储 `_markedRoot`，供子类查询 DOM 创建只读视图。
 *
 * 编辑器 DOM 结构：
 * ```
 * [data-type] div (_markedRoot)
 *   └── .editor-wrapper (wrapper)
 *        ├── .editor-toolbar
 *        │    ├── .editor-toolbar-left (_toolbar)  ← 子类插入语言选择等控件
 *        │    └── .block-actions (_actions)        ← 删除/取消/提交按钮
 *        └── 编辑区 (_editor)                       ← 子类 _createEditor() 创建
 * ```
 *
 * 生命周期：
 * ```
 * mount()  →  打开编辑器，保存原始内容，插入 wrapper
 * commit() →  收集数据，写回 _markedRoot，触发 onCommit
 * close()  →  恢复原始内容，触发 onClose
 * delete() →  移除 block，触发 onDelete
 * ```
 */
export abstract class AbstractEditor {
  /** 编辑器外壳 DOM 元素 */
  readonly wrapper!: HTMLElement;
  /** 宿主注入的生命周期回调 */
  protected _callbacks!: EditorCallbacks;
  /** 统一容器：编辑模式为 [data-type] div，渲染模式为 renderRoot */
  protected _markedRoot: HTMLElement;
  /** 编辑区 DOM，由 _createEditor() 创建 */
  protected _editor!: HTMLElement;
  /** 工具栏右侧操作按钮容器 */
  protected _actions!: HTMLElement;
  /** 工具栏左侧容器，子类可插入自定义控件 */
  protected _toolbar!: HTMLElement;

  /** 编辑前 _markedRoot 原始 innerHTML，close 时恢复 */
  private _savedContent: string = '';

  /**
   * 统一构造入口。
   * @param element    带 data-marked 的容器 div 或宿主 renderRoot
   * @param callbacks  生命周期回调；不传进入渲染器模式
   */
  constructor(element: HTMLElement, callbacks?: EditorCallbacks) {
    this._markedRoot = element;
    if (callbacks) {
      this._callbacks = callbacks;
      this._editor = this._createEditor();

      this._actions = Object.assign(document.createElement('div'), {
        className: 'block-actions',
        innerHTML: btnOk + btnCancel + btnDelete
      });
      this._actions.style.cssText = 'display:flex;gap:4px;';

      this._toolbar = Object.assign(document.createElement('div'), {
        className: 'editor-toolbar-left'
      });

      const toolbar = Object.assign(document.createElement('div'), { className: 'editor-toolbar' });
      toolbar.style.cssText = 'display:flex;align-items:center;justify-content:space-between;margin-bottom:-4px;';
      toolbar.append(this._toolbar, this._actions);

      this.wrapper = Object.assign(document.createElement('div'), { className: 'editor-wrapper' });
      this.wrapper.style.cssText = 'display:flex;flex-direction:column;gap:4px;';
      this.wrapper.append(toolbar, this._editor);

      this.wrapper.addEventListener('mousedown', this._onAction);
      this._editor.addEventListener('keydown', this._onKey);
    }
  }

  /** 创建编辑区 DOM 元素。编辑器子类必须覆写，渲染器子类无需。 */
  protected _createEditor(): HTMLElement {
    return document.createElement('div');
  }

  /** 收集提交数据。编辑器子类必须覆写，返回 raw（写入 data-marked）和 html（写入 innerHTML）。 */
  protected _commitCollect(): { raw: string; html: string } {
    return { raw: '', html: '' };
  }

  /** 销毁编辑器内部资源（如 CM6 EditorView）。子类按需覆写。 */
  protected _destroyEditor(): void {
  }

  /** 工具栏按钮点击代理。通过 data-action 区分 confirm / delete / cancel。 */
  private _onAction = (ev: MouseEvent): void => {
    const btn = (ev.target as HTMLElement).closest('[data-action]');
    if (!btn) return;
    ev.preventDefault();
    const action = btn.getAttribute('data-action');
    if (action === 'confirm') {
      this.commit();
    } else if (action === 'delete') {
      this.delete();
    } else {
      this.close();
    }
  };

  /** 编辑区键盘事件。Escape 取消，Ctrl+Enter 提交。 */
  private _onKey = (ev: KeyboardEvent): void => {
    if (ev.key === 'Escape') { ev.preventDefault(); this.close(); }
    else if (ev.key === 'Enter' && (ev.ctrlKey || ev.metaKey)) { ev.preventDefault(); this.commit(); }
  };

  /** 打开编辑器。保存 _markedRoot 原始内容，清空并插入 wrapper，聚焦编辑区。 */
  mount(): void {
    this._markedRoot.classList.add('is-editing');
    this._savedContent = this._markedRoot.innerHTML;
    this._markedRoot.replaceChildren(this.wrapper);
    this._editor.focus();
  }

  /** 提交编辑。收集数据 → 规范化 → 写回 _markedRoot → 触发 onCommit/onClose。 */
  commit(): void {
    const { raw, html } = this._commitCollect();
    this._markedRoot.setAttribute('data-marked', this.trimBlock(raw));
    this._markedRoot.innerHTML = this._callbacks.transform ? this._callbacks.transform(html) : html;
    this._markedRoot.classList.remove('is-editing');
    this._teardown();
    this._callbacks.onCommit(raw);
    this._callbacks.onClose();
  }

  /** 取消编辑。销毁编辑器，恢复 _markedRoot 原始内容，触发 onClose。 */
  close(): void {
    this._markedRoot.classList.remove('is-editing');
    this._destroyEditor();
    this._markedRoot.innerHTML = this._savedContent;
    this._teardown();
    this._callbacks.onClose();
  }

  /** 删除当前 block。清理 → 移除 DOM 元素 → 触发 onDelete。 */
  protected delete(): void {
    this._destroyEditor();
    this._teardown();
    this._callbacks.onClose();
    this._markedRoot.remove();
    this._callbacks.onDelete?.();
  }

  /** 解绑事件监听（commit / close / delete 共用） */
  private _teardown(): void {
    this.wrapper.removeEventListener('mousedown', this._onAction);
    this._editor.removeEventListener('keydown', this._onKey);
  }

  /** 去除首尾空白及空行，用于提交时规范化 data-marked 内容。 */
  private trimBlock(text: string): string {
    const trimmed = text.trim();
    if (!trimmed) return '';
    const lines = trimmed.split('\n');
    let start = 0;
    let end = lines.length;
    while (start < end && lines[start].trim() === '') start++;
    while (end > start && lines[end - 1].trim() === '') end--;
    return lines.slice(start, end).join('\n');
  }

  /* ──────────────────────── 静态工具方法 ──────────────────────── */

  /** HTML 实体转义：& < > → &amp; &lt; &gt; */
  static escapeHtml(text: string): string {
    return text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');
  }

  /** 生成代码块语法高亮占位 HTML：`<pre><code data-lang="...">转义后代码</code></pre>` */
  static highlight(lang: string, code: string): string {
    const escaped = this.escapeHtml(code);
    if (!lang) {
      return `<pre><code>${escaped}</code></pre>\n`;
    }
    return `<pre><code class="language-${lang}" data-lang="${lang}">${escaped}</code></pre>\n`;
  }

  /** 根据语言标识符获取 CM6 LanguageSupport。支持别名（js→javascript），未找到返回 null。 */
  static getLanguageExtension(lang: string): LanguageSupport | null {
    if (!lang) return null;
    _initRegistry();
    return _langRegistry[_normalizeLang(lang)] ?? null;
  }

  /** 返回所有已注册的语言标识符列表（去重、排序）。 */
  static getSupportedLanguages(): string[] {
    _initRegistry();
    return Object.keys(_langRegistry).sort();
  }

  /** 将语言别名归一化为标准名称。例：js→javascript、yml→yaml。 */
  static normalizeLang(lang: string): string {
    return _normalizeLang(lang);
  }
}
